INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, "リリ", 2, 1, 24001, 321, 0, 40011, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, "クリア", 2, 1, 24001, 322, 0, 40011, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 2, 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, "プレシア", 2, 1, 24001, 323, 0, 40011, "んーと。\nこれ、あげる。\nはい", 3, 126101);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, "リリ", 2, 1, 24001, 324, 0, 40011, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 4, 125801);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, "クリア", 2, 1, 24001, 325, 0, 40011, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 5, 126001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, "プレシア", 2, 1, 24001, 326, 0, 40011, "お兄。\nきてくれて、うれしい", 6, 126101);
